def load_config(path: str) -> List[TenantSpec]:
    with open(path, "r", encoding="utf-8") as f:
        raw = json.load(f)

    tenants_raw = raw.get("tenants")
    if not isinstance(tenants_raw, list):
        raise ValueError("Config must contain a 'tenants' list")

    tenants: List[TenantSpec] = []
    for tenant_item in tenants_raw:
        users: List[UserSpec] = []
        for user_item in tenant_item.get("users", []):
            perms_raw = user_item.get("permissions", {})
            perms = UserPermission(
                configure=perms_raw.get("configure", ".*"),
                write=perms_raw.get("write", ".*"),
                read=perms_raw.get("read", ".*"),
            )
            users.append(
                UserSpec(
                    username=user_item["username"],
                    password=user_item.get("password"),
                    tags=user_item.get("tags", []),
                    permissions=perms,
                )
            )
        tenants.append(
            TenantSpec(
                name=tenant_item.get("name", tenant_item["vhost"]),
                vhost=tenant_item["vhost"],
                users=users,
            )
        )
    return tenants


